class Solution:
    def isValid(self, s: str) -> bool:
        stack = []
        pairs = {')': '(', ']': '[', '}': '{'}
        for c in s:
            if c in pairs:
                if not stack or stack[-1] != pairs[c]:
                    return False
                stack.pop()
            else:
                stack.append(c)
        return len(stack) == 0

solution_js:
var isValid = function(s) {
    const stack = [];
    const pairs = {')': '(', ']': '[', '}': '{'};
    for (const c of s) {
        if (pairs[c]) {
            if (!stack.length || stack[stack.length - 1] !== pairs[c]) return false;
            stack.pop();
        } else {
            stack.push(c);
        }
    }
    return stack.length === 0;
};

