            for (let j = 0; j < word.length; j++) {
                const pat = word.slice(0,j) + '*' + word.slice(j+1);
                for (const nw of (nei.get(pat) || [])) {
                    if (!visit.has(nw)) { visit.add(nw); queue.push(nw); }
                }
            }
        }
        res++;
    }
    return 0;
};

