    function dfs(i, buying) {
        if (i >= prices.length) return 0;
        const key = i + ',' + buying;
        if (dp.has(key)) return dp.get(key);
        const cooldown = dfs(i + 1, buying);
        let res;
        if (buying) {
            res = Math.max(dfs(i + 1, false) - prices[i], cooldown);
        } else {
            res = Math.max(dfs(i + 2, true) + prices[i], cooldown);
        }
        dp.set(key, res);
        return res;
    }
    return dfs(0, true);
};

