    let dp = new Map();
    dp.set(0, 1);
    for (const n of nums) {
        const next = new Map();
        for (const [s, count] of dp) {
            next.set(s + n, (next.get(s + n) || 0) + count);
            next.set(s - n, (next.get(s - n) || 0) + count);
        }
        dp = next;
    }
    return dp.get(target) || 0;
};

