solution_python:
def longestIncreasingPath(self, matrix: List[List[int]]) -> int:
    rows, cols = len(matrix), len(matrix[0])
    dp = {}
    def dfs(r, c, prevVal):
        if r < 0 or c < 0 or r >= rows or c >= cols or matrix[r][c] <= prevVal:
            return 0
        if (r, c) in dp:
            return dp[(r, c)]
        res = 1
        for dr, dc in [(1,0),(-1,0),(0,1),(0,-1)]:
            res = max(res, 1 + dfs(r+dr, c+dc, matrix[r][c]))
        dp[(r, c)] = res
        return res
    result = 0
    for r in range(rows):
        for c in range(cols):
            result = max(result, dfs(r, c, float('-inf')))
    return result

solution_js:
var longestIncreasingPath = function(matrix) {
    const rows = matrix.length, cols = matrix[0].length;
    const dp = Array.from({length: rows}, () => new Array(cols).fill(0));
    function dfs(r, c, prev) {
        if (r < 0 || c < 0 || r >= rows || c >= cols || matrix[r][c] <= prev) return 0;
        if (dp[r][c]) return dp[r][c];
        let res = 1;
        for (const [dr,dc] of [[1,0],[-1,0],[0,1],[0,-1]])
            res = Math.max(res, 1 + dfs(r+dr, c+dc, matrix[r][c]));
        dp[r][c] = res;
        return res;
    }
    let result = 0;
    for (let r = 0; r < rows; r++)
        for (let c = 0; c < cols; c++)
            result = Math.max(result, dfs(r, c, -Infinity));
    return result;
};

