    tickets.sort().reverse();
    for (const [src, dst] of tickets) {
        if (!graph.has(src)) graph.set(src, []);
        graph.get(src).push(dst);
    }
    const res = [];
    function dfs(node) {
        const dests = graph.get(node) || [];
        while (dests.length) dfs(dests.pop());
        res.push(node);
    }
    dfs('JFK');
    return res.reverse();
};

