def minCostConnectPoints(self, points: List[List[int]]) -> int:
    n = len(points)
    visited = set()
    heap = [(0, 0)]  # (cost, point_index)
    total = 0
    while len(visited) < n:
        cost, i = heapq.heappop(heap)
        if i in visited:
            continue
        visited.add(i)
        total += cost
        for j in range(n):
            if j not in visited:
                dist = abs(points[i][0] - points[j][0]) + abs(points[i][1] - points[j][1])
                heapq.heappush(heap, (dist, j))
    return total

solution_js:
var minCostConnectPoints = function(points) {
    const n = points.length;
    const visited = new Set();
    const heap = new MinPriorityQueue({ priority: x => x[0] });
    heap.enqueue([0, 0]);
    let total = 0;
    while (visited.size < n) {
        const [cost, i] = heap.dequeue().element;
        if (visited.has(i)) continue;
        visited.add(i);
        total += cost;
        for (let j = 0; j < n; j++) {
            if (!visited.has(j)) {
                const dist = Math.abs(points[i][0]-points[j][0]) + Math.abs(points[i][1]-points[j][1]);
                heap.enqueue([dist, j]);
            }
        }
    }
    return total;
};

solution_python:
def networkDelayTime(self, times: List[List[int]], n: int, k: int) -> int:
    graph = defaultdict(list)
    for u, v, w in times:
        graph[u].append((v, w))
    heap = [(0, k)]
    visited = set()
    t = 0
    while heap:
        w, node = heapq.heappop(heap)
        if node in visited:
            continue
        visited.add(node)
        t = max(t, w)
        for nei, w2 in graph[node]:
            if nei not in visited:
                heapq.heappush(heap, (w + w2, nei))
    return t if len(visited) == n else -1

solution_js:
var networkDelayTime = function(times, n, k) {
    const graph = new Map();
    for (const [u, v, w] of times) {
        if (!graph.has(u)) graph.set(u, []);
        graph.get(u).push([v, w]);
    }
    const heap = new MinPriorityQueue({ priority: x => x[0] });
    heap.enqueue([0, k]);
    const visited = new Set();
    let t = 0;
    while (heap.size()) {
        const [w, node] = heap.dequeue().element;
        if (visited.has(node)) continue;
        visited.add(node);
        t = Math.max(t, w);
        for (const [nei, w2] of (graph.get(node) || []))
            if (!visited.has(nei)) heap.enqueue([w + w2, nei]);
    }
    return visited.size === n ? t : -1;
};

solution_python:
def swimInWater(self, grid: List[List[int]]) -> int:
    n = len(grid)
    visited = set()
    heap = [(grid[0][0], 0, 0)]
    visited.add((0, 0))
    while heap:
        t, r, c = heapq.heappop(heap)
        if r == n - 1 and c == n - 1:
            return t
        for dr, dc in [(1,0),(-1,0),(0,1),(0,-1)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < n and 0 <= nc < n and (nr, nc) not in visited:
                visited.add((nr, nc))
                heapq.heappush(heap, (max(t, grid[nr][nc]), nr, nc))
    return -1

solution_js:
var swimInWater = function(grid) {
    const n = grid.length;
    const visited = new Set();
    const heap = new MinPriorityQueue({ priority: x => x[0] });
    heap.enqueue([grid[0][0], 0, 0]);
    visited.add('0,0');
    while (heap.size()) {
        const [t, r, c] = heap.dequeue().element;
        if (r === n-1 && c === n-1) return t;
        for (const [dr,dc] of [[1,0],[-1,0],[0,1],[0,-1]]) {
            const nr = r+dr, nc = c+dc;
            const key = nr+','+nc;
            if (nr >= 0 && nc >= 0 && nr < n && nc < n && !visited.has(key)) {
                visited.add(key);
                heap.enqueue([Math.max(t, grid[nr][nc]), nr, nc]);
            }
        }
    }
    return -1;
};

solution_python:
def alienOrder(self, words: List[str]) -> str:
    adj = {c: set() for w in words for c in w}
    for i in range(len(words) - 1):
        w1, w2 = words[i], words[i + 1]
        minLen = min(len(w1), len(w2))
        if len(w1) > len(w2) and w1[:minLen] == w2[:minLen]:
            return ''
        for j in range(minLen):
            if w1[j] != w2[j]:
                adj[w1[j]].add(w2[j])
                break
    visited = {}
    res = []
    def dfs(c):
        if c in visited:
            return visited[c]
        visited[c] = True
        for nei in adj[c]:
            if dfs(nei):
                return True
        visited[c] = False
        res.append(c)
        return False
    for c in adj:
        if dfs(c):
            return ''
    return ''.join(res[::-1])

solution_js:
var alienOrder = function(words) {
    const adj = new Map();
    for (const w of words) for (const c of w) if (!adj.has(c)) adj.set(c, new Set());
    for (let i = 0; i < words.length - 1; i++) {
        const w1 = words[i], w2 = words[i+1];
        const minLen = Math.min(w1.length, w2.length);
        if (w1.length > w2.length && w1.slice(0, minLen) === w2.slice(0, minLen)) return '';
        for (let j = 0; j < minLen; j++) {
            if (w1[j] !== w2[j]) { adj.get(w1[j]).add(w2[j]); break; }
        }
    }
    const visited = new Map();
    const res = [];
    function dfs(c) {
        if (visited.has(c)) return visited.get(c);
        visited.set(c, true);
        for (const nei of adj.get(c)) if (dfs(nei)) return true;
        visited.set(c, false);
        res.push(c);
        return false;
    }
    for (const c of adj.keys()) if (dfs(c)) return '';
    return res.reverse().join('');
};

solution_python:
def findCheapestPrice(self, n: int, flights: List[List[int]], src: int, dst: int, k: int) -> int:
    prices = [float('inf')] * n
    prices[src] = 0
    for i in range(k + 1):
        tmpPrices = prices[:]
        for s, d, p in flights:
            if prices[s] == float('inf'):
                continue
            if prices[s] + p < tmpPrices[d]:
                tmpPrices[d] = prices[s] + p
        prices = tmpPrices
    return prices[dst] if prices[dst] != float('inf') else -1

solution_js:
var findCheapestPrice = function(n, flights, src, dst, k) {
    let prices = new Array(n).fill(Infinity);
    prices[src] = 0;
    for (let i = 0; i <= k; i++) {
        const tmp = [...prices];
        for (const [s, d, p] of flights) {
            if (prices[s] === Infinity) continue;
            if (prices[s] + p < tmp[d]) tmp[d] = prices[s] + p;
        }
        prices = tmp;
    }
    return prices[dst] === Infinity ? -1 : prices[dst];
};
